import { createPost } from './actions';
import { getPosts } from './posts-data';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main style={{ fontFamily: 'Arial, sans-serif', padding: '32px', maxWidth: '760px', margin: '0 auto' }}>
      <h1>Posts</h1>
      <p>Create a post. The list is cached with the <code>posts</code> tag and invalidated with <code>updateTag</code>.</p>

      <form action={createPost} style={{ display: 'grid', gap: '12px', marginTop: '24px', marginBottom: '32px' }}>
        <input
          name="title"
          type="text"
          placeholder="Post title"
          aria-label="Post title"
          style={{ padding: '12px 14px', fontSize: '16px' }}
          required
        />
        <textarea
          name="body"
          placeholder="Post body"
          aria-label="Post body"
          rows={5}
          style={{ padding: '12px 14px', fontSize: '16px', resize: 'vertical' }}
          required
        />
        <button type="submit" style={{ padding: '12px 16px', fontSize: '16px', cursor: 'pointer' }}>
          Create post
        </button>
      </form>

      <section>
        <h2>Cached posts</h2>
        <ul style={{ listStyle: 'none', padding: 0, display: 'grid', gap: '16px' }}>
          {posts.map((post) => (
            <li key={post.id} style={{ border: '1px solid #ddd', borderRadius: '12px', padding: '16px' }}>
              <h3 style={{ marginTop: 0, marginBottom: '8px' }}>{post.title}</h3>
              <p style={{ marginTop: 0, marginBottom: '8px' }}>{post.body}</p>
              <small>{new Date(post.createdAt).toLocaleString('en-US', { timeZone: 'UTC' })}</small>
            </li>
          ))}
        </ul>
      </section>
    </main>
  );
}

