'use server';

import { updateTag } from 'next/cache';
import { redirect } from 'next/navigation';

import { addPost } from './posts-data';

export async function createPost(formData: FormData) {
  const title = String(formData.get('title') ?? '').trim();
  const body = String(formData.get('body') ?? '').trim();

  if (!title || !body) {
    throw new Error('Both title and body are required.');
  }

  await addPost({ title, body });

  updateTag('posts');
  redirect('/');
}

---
import { cacheTag } from 'next/cache';

export type Post = {
  id: number;
  title: string;
  body: string;
  createdAt: string;
};

const posts: Post[] = [
  {
    id: 1,
    title: 'Welcome to Posts',
    body: 'This starter uses a cache tag named "posts" to cache the list.',
    createdAt: new Date('2026-07-15T00:00:00.000Z').toISOString(),
  },
];

let nextId = posts.length + 1;

export async function getPosts() {
  'use cache';

  cacheTag('posts');

  return posts.map((post) => ({ ...post }));
}

export async function addPost(input: { title: string; body: string }) {
  const post: Post = {
    id: nextId++,
    title: input.title,
    body: input.body,
    createdAt: new Date().toISOString(),
  };

  posts.unshift(post);

  return post;
}

